 33→
 34→BridgeServer::BridgeServer(
 35→    std::shared_ptr<TopicSourceInterface> topic_source,
 36→    std::shared_ptr<SubscriptionManagerInterface> subscription_manager, std::shared_ptr<MiddlewareInterface> middleware,
 37→    int port, double session_timeout, double publish_rate)
 38→    : topic_source_(std::move(topic_source)),
 39→      subscription_manager_(std::move(subscription_manager)),
 40→      middleware_(std::move(middleware)),
 41→      port_(port),
 42→      session_timeout_(session_timeout),
 43→      publish_rate_(publish_rate),
 44→      initialized_(false),
 45→      total_messages_published_(0),
 46→      total_bytes_published_(0),
 47→      publish_cycles_(0) {}
 48→
 49→BridgeServer::~BridgeServer() {
 50→  // Shut down the middleware before members are destroyed so that
 51→  // disconnect callbacks (which capture `this`) cannot fire into
 52→  // a partially destroyed BridgeServer.
 53→  if (middleware_) {
 54→    middleware_->shutdown();
 55→  }
 56→}
 57→
 58→bool BridgeServer::initialize() {
 59→  if (initialized_) {
 60→    spdlog::warn("Bridge server already initialized");
 61→    return true;
 62→  }
 63→
 64→  spdlog::info("Initializing bridge server...");
 65→
 66→  if (publish_rate_ <= 0.0) {
 67→    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
 68→    return false;
 69→  }
 70→
 71→  if (port_ < 1 || port_ > 65535) {
 72→    spdlog::error("Invalid port: {} (must be 1-65535)", port_);
 73→    return false;
 74→  }
 75→
 76→  message_buffer_ = std::make_shared<MessageBuffer>();
 77→  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 78→
 79→  spdlog::info("Core components created");
 80→
 81→  // Set the global message callback to feed into message buffer
 82→  subscription_manager_->set_message_callback(
 83→      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 84→        {
 85→          std::lock_guard<std::mutex> lock(stats_mutex_);
 86→          topic_receive_counts_[topic_name]++;
 87→        }
 88→        if (message_buffer_) {
 89→          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 90→        }
 91→      });
 92→
 93→  // Register disconnect callback before middleware init to avoid missing events
 94→  middleware_->set_on_disconnect([this](const std::string& client_id) {
 95→    spdlog::info("Client disconnected: '{}'", client_id);
 96→    cleanup_session(client_id);
 97→  });
 98→
 99→  // Initialize middleware (may start accepting connections immediately)
100→  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
101→  if (!result) {
102→    spdlog::error("Failed to initialize middleware: {}", result.error());
103→    return false;
104→  }
105→  spdlog::info("Middleware initialized (port: {})", port_);
106→
107→  initialized_ = true;
108→  spdlog::info("Bridge server initialization complete");
109→
110→  return true;
111→}
112→
113→bool BridgeServer::process_requests() {
114→  if (!initialized_) {
115→    spdlog::error("Bridge server not initialized");
116→    return false;
117→  }
118→
119→  // Receive request (non-blocking with timeout)
120→  std::vector<uint8_t> request_data;
121→  std::string client_id;
122→  bool received = middleware_->receive_request(request_data, client_id);
123→
124→  if (!received || request_data.empty()) {
125→    return false;
126→  }
127→
128→  std::string request(request_data.begin(), request_data.end());
129→  if (client_id.empty()) {
130→    spdlog::warn("Received request with no client identity");
131→    return true;
132→  }
133→
134→  // Parse request JSON
135→  std::string response;
136→  json request_json;
137→  try {
138→    request_json = json::parse(request);
139→
140→    if (!request_json.contains("command")) {
141→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
142→    } else {
143→      std::string command = request_json["command"];
144→
145→      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
146→
147→      if (command == "get_topics") {
148→        response = handle_get_topics(client_id, request_json);
149→      } else if (command == "subscribe") {
150→        response = handle_subscribe(client_id, request_json);
151→      } else if (command == "unsubscribe") {
152→        response = handle_unsubscribe(client_id, request_json);
153→      } else if (command == "heartbeat") {
154→        response = handle_heartbeat(client_id, request_json);
155→      } else if (command == "pause") {
156→        response = handle_pause(client_id, request_json);
157→      } else if (command == "resume") {
158→        response = handle_resume(client_id, request_json);
159→      } else {
160→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
161→      }
162→    }
163→  } catch (const json::exception& e) {
164→    spdlog::error("JSON parse error: {}", e.what());
165→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
166→  } catch (const std::exception& e) {
167→    spdlog::error("Error processing request: {}", e.what());
168→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
169→  }
170→
171→  // Send response to the specific client
172→  std::vector<uint8_t> response_data(response.begin(), response.end());
173→  if (!middleware_->send_reply(client_id, response_data)) {
174→    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
175→    cleanup_session(client_id);
176→  }
177→  return true;
178→}
