180→std::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
181→  if (!session_manager_->session_exists(client_id)) {
182→    session_manager_->create_session(client_id);
183→    spdlog::info("Created new session for client '{}'", client_id);
184→  }
185→
186→  session_manager_->update_heartbeat(client_id);
187→
188→  auto topics = topic_source_->get_topics();
189→
190→  json response;
191→  response["status"] = "success";
192→  response["topics"] = json::array();
193→
194→  for (const auto& topic : topics) {
195→    json topic_entry;
196→    topic_entry["name"] = topic.name;
197→    topic_entry["type"] = topic.type;
198→    response["topics"].push_back(topic_entry);
199→  }
200→
201→  inject_response_fields(response, request);
202→
203→  spdlog::info("Returning {} topics to client '{}'", topics.size(), client_id);
204→
205→  return response.dump();
206→}
