208→std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
209→  if (!session_manager_->session_exists(client_id)) {
210→    session_manager_->create_session(client_id);
211→    spdlog::info("Created new session for client '{}'", client_id);
212→  }
213→
214→  session_manager_->update_heartbeat(client_id);
215→
216→  if (!request.contains("topics")) {
217→    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
218→  }
219→
220→  if (!request["topics"].is_array()) {
221→    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
222→  }
223→
224→  auto current_subs = session_manager_->get_subscriptions(client_id);
225→
226→  // Parse requested topics — supports mixed array of strings and objects:
227→  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
228→  std::unordered_map<std::string, double> requested_topics;
229→  for (const auto& topic : request["topics"]) {
230→    if (topic.is_string()) {
231→      requested_topics[topic.get<std::string>()] = 0.0;
232→    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
233→      double rate_hz = 0.0;
234→      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
235→        rate_hz = topic["max_rate_hz"].get<double>();
236→        if (rate_hz < 0.0) {
237→          rate_hz = 0.0;
238→        }
239→      }
240→      requested_topics[topic["name"].get<std::string>()] = rate_hz;
241→    }
242→  }
243→
244→  // Determine which topics to add (additive model — subscribe only adds, never removes)
245→  std::vector<std::string> topics_to_add;
246→  for (const auto& [topic, rate] : requested_topics) {
247→    if (current_subs.find(topic) == current_subs.end()) {
248→      topics_to_add.push_back(topic);
249→    }
250→  }
251→
252→  // Build topic name → type lookup from topic source
253→  auto available_topics = topic_source_->get_topics();
254→  std::unordered_map<std::string, std::string> topic_types;
255→  for (const auto& topic : available_topics) {
256→    topic_types[topic.name] = topic.type;
257→  }
258→
259→  // Subscribe to new topics — track successes and failures
260→  json schemas = json::object();
261→  json failures = json::array();
262→
263→  for (const auto& topic_name : topics_to_add) {
264→    if (topic_types.find(topic_name) == topic_types.end()) {
265→      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
266→      json failure;
267→      failure["topic"] = topic_name;
268→      failure["reason"] = "Topic does not exist";
269→      failures.push_back(failure);
270→      continue;
271→    }
272→
273→    std::string topic_type = topic_types[topic_name];
274→
275→    // Get schema BEFORE subscribing to avoid corrupting the reference count
276→    // if schema extraction fails after subscribe() increments it.
277→    std::string schema;
278→    try {
279→      schema = topic_source_->get_schema(topic_name);
280→    } catch (const std::exception& e) {
281→      spdlog::error("Failed to get schema for topic '{}': {}", topic_name, e.what());
282→      json failure;
283→      failure["topic"] = topic_name;
284→      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
285→      failures.push_back(failure);
286→      continue;
287→    }
288→
289→    if (schema.empty()) {
290→      spdlog::error("Empty schema for topic '{}' (type: {})", topic_name, topic_type);
291→      json failure;
292→      failure["topic"] = topic_name;
293→      failure["reason"] = "Schema extraction returned empty definition";
294→      failures.push_back(failure);
295→      continue;
296→    }
297→
298→    // Subscribe via subscription manager (ref-counted)
299→    bool success = subscription_manager_->subscribe(topic_name, topic_type);
300→    if (!success) {
301→      spdlog::error("Failed to subscribe to topic '{}'", topic_name);
302→      json failure;
303→      failure["topic"] = topic_name;
304→      failure["reason"] = "Subscription manager failed to create subscription";
305→      failures.push_back(failure);
306→      continue;
307→    }
308→
309→    // Immediately add to session. If session is gone (client disconnected
310→    // between subscribe and now), roll back the ref count.
311→    if (!session_manager_->add_subscription(client_id, topic_name, requested_topics[topic_name])) {
312→      spdlog::warn("Session gone for client '{}', rolling back subscribe for '{}'", client_id, topic_name);
313→      subscription_manager_->unsubscribe(topic_name);
314→      continue;
315→    }
316→
317→    nlohmann::json schema_obj;
318→    schema_obj["encoding"] = topic_source_->schema_encoding();
319→    schema_obj["definition"] = schema;
320→    schemas[topic_name] = schema_obj;
321→
322→    spdlog::info("Client '{}' subscribed to topic '{}' (type: {})", client_id, topic_name, topic_type);
323→  }
324→
325→  // Update rates for topics that were already subscribed but may have a new rate
326→  for (const auto& [topic, rate] : requested_topics) {
327→    if (current_subs.find(topic) != current_subs.end()) {
328→      session_manager_->add_subscription(client_id, topic, rate);
329→    }
330→  }
331→
332→  // Build response
333→  json response;
334→  if (failures.empty()) {
335→    response["status"] = "success";
336→  } else if (schemas.empty()) {
337→    response["status"] = "error";
338→    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
339→    response["message"] = "Failed to subscribe to all requested topics";
340→  } else {
341→    response["status"] = "partial_success";
342→    response["message"] = "Some subscriptions failed";
343→  }
344→
345→  response["schemas"] = schemas;
346→  if (!failures.empty()) {
347→    response["failures"] = failures;
348→  }
349→
350→  // Include rate limits in response for topics with non-zero rates
351→  json rate_limits = json::object();
352→  auto updated_subs = session_manager_->get_subscriptions(client_id);
353→  for (const auto& [topic, rate] : updated_subs) {
354→    if (rate > 0.0) {
355→      rate_limits[topic] = rate;
356→    }
357→  }
358→  if (!rate_limits.empty()) {
359→    response["rate_limits"] = rate_limits;
360→  }
361→
362→  inject_response_fields(response, request);
363→
364→  return response.dump();
365→}
