367→std::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
368→  if (!session_manager_->session_exists(client_id)) {
369→    session_manager_->create_session(client_id);
370→    spdlog::info("Created new session for client '{}'", client_id);
371→  }
372→
373→  session_manager_->update_heartbeat(client_id);
374→
375→  if (!request.contains("topics") || !request["topics"].is_array()) {
376→    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
377→  }
378→
379→  auto current_subs = session_manager_->get_subscriptions(client_id);
380→
381→  std::vector<std::string> removed;
382→
383→  for (const auto& topic_item : request["topics"]) {
384→    std::string topic_name;
385→    if (topic_item.is_string()) {
386→      topic_name = topic_item.get<std::string>();
387→    } else if (topic_item.is_object() && topic_item.contains("name") && topic_item["name"].is_string()) {
388→      topic_name = topic_item["name"].get<std::string>();
389→    } else {
390→      continue;
391→    }
392→
393→    if (current_subs.find(topic_name) != current_subs.end()) {
394→      subscription_manager_->unsubscribe(topic_name);
395→      current_subs.erase(topic_name);
396→      removed.push_back(topic_name);
397→
398→      spdlog::info("Client '{}' unsubscribed from topic '{}'", client_id, topic_name);
399→    }
400→  }
401→
402→  session_manager_->update_subscriptions(client_id, current_subs);
403→
404→  json response;
405→  response["status"] = "success";
406→  response["removed"] = removed;
407→  inject_response_fields(response, request);
408→
409→  return response.dump();
410→}
