412→std::string BridgeServer::handle_heartbeat(const std::string& client_id, const nlohmann::json& request) {
413→  if (!session_manager_->session_exists(client_id)) {
414→    session_manager_->create_session(client_id);
415→    spdlog::info("Created new session for client '{}'", client_id);
416→  }
417→
418→  session_manager_->update_heartbeat(client_id);
419→
420→  spdlog::debug("Heartbeat received from client '{}'", client_id);
421→
422→  json response;
423→  response["status"] = "ok";
424→  inject_response_fields(response, request);
425→
426→  return response.dump();
427→}
