429→std::string BridgeServer::handle_pause(const std::string& client_id, const nlohmann::json& request) {
430→  if (!session_manager_->session_exists(client_id)) {
431→    session_manager_->create_session(client_id);
432→    spdlog::info("Created new session for client '{}'", client_id);
433→  }
434→
435→  session_manager_->update_heartbeat(client_id);
436→
437→  if (session_manager_->is_paused(client_id)) {
438→    spdlog::debug("Client '{}' already paused", client_id);
439→    json response;
440→    response["status"] = "ok";
441→    response["paused"] = true;
442→    inject_response_fields(response, request);
443→    return response.dump();
444→  }
445→
446→  session_manager_->set_paused(client_id, true);
447→
448→  // Decrement ref counts for all subscribed topics
449→  auto subs = session_manager_->get_subscriptions(client_id);
450→  for (const auto& [topic, rate] : subs) {
451→    subscription_manager_->unsubscribe(topic);
452→    spdlog::debug("Decremented ref count for topic '{}' (client '{}' paused)", topic, client_id);
453→  }
454→
455→  spdlog::info("Client '{}' paused ({} topics refs decremented)", client_id, subs.size());
456→
457→  json response;
458→  response["status"] = "ok";
459→  response["paused"] = true;
460→  inject_response_fields(response, request);
461→  return response.dump();
462→}
463→
464→std::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
465→  if (!session_manager_->session_exists(client_id)) {
466→    session_manager_->create_session(client_id);
467→    spdlog::info("Created new session for client '{}'", client_id);
468→  }
469→
470→  session_manager_->update_heartbeat(client_id);
471→
472→  if (!session_manager_->is_paused(client_id)) {
473→    spdlog::debug("Client '{}' not paused", client_id);
474→    json response;
475→    response["status"] = "ok";
476→    response["paused"] = false;
477→    inject_response_fields(response, request);
478→    return response.dump();
479→  }
480→
481→  session_manager_->set_paused(client_id, false);
482→
483→  // Build topic name → type lookup for subscribe calls
484→  auto available_topics = topic_source_->get_topics();
485→  std::unordered_map<std::string, std::string> topic_types;
486→  for (const auto& t : available_topics) {
487→    topic_types[t.name] = t.type;
488→  }
489→
490→  // Increment ref counts for all subscribed topics
491→  auto subs = session_manager_->get_subscriptions(client_id);
492→  std::vector<std::string> failed_topics;
493→  for (const auto& [topic, rate] : subs) {
494→    auto type_it = topic_types.find(topic);
495→    if (type_it == topic_types.end()) {
496→      spdlog::warn("Topic '{}' no longer exists, cannot re-subscribe for client '{}'", topic, client_id);
497→      failed_topics.push_back(topic);
498→      continue;
499→    }
500→    bool ok = subscription_manager_->subscribe(topic, type_it->second);
501→    if (ok) {
502→      spdlog::debug("Incremented ref count for topic '{}' (client '{}' resumed)", topic, client_id);
503→    } else {
504→      spdlog::warn("Topic '{}' subscription failed on resume for client '{}'", topic, client_id);
505→      failed_topics.push_back(topic);
506→    }
507→  }
508→
509→  // Remove failed topics from session to prevent ref-count underflow on disconnect
510→  for (const auto& topic : failed_topics) {
511→    session_manager_->remove_subscription(client_id, topic);
512→  }
513→
514→  spdlog::info(
515→      "Client '{}' resumed ({} topics re-subscribed, {} failed)", client_id, subs.size() - failed_topics.size(),
516→      failed_topics.size());
517→
518→  json response;
519→  response["status"] = "ok";
520→  response["paused"] = false;
521→  inject_response_fields(response, request);
522→  return response.dump();
523→}
