525→void BridgeServer::inject_response_fields(nlohmann::json& response, const nlohmann::json& request) const {
526→  response["protocol_version"] = kProtocolVersion;
527→  if (request.contains("id") && request["id"].is_string()) {
528→    response["id"] = request["id"];
529→  }
530→}
