532→std::string BridgeServer::create_error_response(
533→    const std::string& error_code, const std::string& message, const nlohmann::json& request) const {
534→  json response;
535→  response["status"] = "error";
536→  response["error_code"] = error_code;
537→  response["message"] = message;
538→  inject_response_fields(response, request);
