543→void BridgeServer::check_session_timeouts() {
544→  if (!initialized_) {
545→    return;
546→  }
547→
548→  auto timed_out_sessions = session_manager_->get_timed_out_sessions();
549→
550→  for (const auto& client_id : timed_out_sessions) {
551→    spdlog::warn("Session timeout for client '{}'", client_id);
552→    cleanup_session(client_id);
553→  }
554→}
555→
556→void BridgeServer::cleanup_session(const std::string& client_id) {
557→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
558→
559→  if (!session_manager_->session_exists(client_id)) {
560→    return;
561→  }
562→
563→  auto subscriptions = session_manager_->get_subscriptions(client_id);
564→  bool was_paused = session_manager_->is_paused(client_id);
565→
566→  // Unsubscribe from all topics (only if not paused — paused clients already decremented ref counts)
567→  if (!was_paused) {
568→    for (const auto& [topic, rate] : subscriptions) {
569→      subscription_manager_->unsubscribe(topic);
570→      spdlog::debug("Unsubscribed client '{}' from topic '{}'", client_id, topic);
571→    }
572→  }
573→
574→  session_manager_->remove_session(client_id);
575→
576→  {
577→    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
578→    last_sent_times_.erase(client_id);
579→  }
580→
581→  spdlog::info("Cleaned up session for client '{}' ({} topics unsubscribed)", client_id, subscriptions.size());
582→}
