593→BridgeServer::StatsSnapshot BridgeServer::snapshot_and_reset_stats() {
594→  std::lock_guard<std::mutex> lock(stats_mutex_);
595→  StatsSnapshot snapshot;
596→  snapshot.topic_receive_counts = std::move(topic_receive_counts_);
597→  topic_receive_counts_.clear();
598→  snapshot.topic_forward_counts = std::move(topic_forward_counts_);
599→  topic_forward_counts_.clear();
600→  snapshot.publish_cycles = publish_cycles_;
601→  publish_cycles_ = 0;
602→  snapshot.total_bytes_published = total_bytes_published_;
603→  total_bytes_published_ = 0;
604→  return snapshot;
605→}
606→
607→void BridgeServer::publish_aggregated_messages() {
608→  if (!initialized_) {
609→    return;
610→  }
611→
612→  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
613→  message_buffer_->move_messages(messages);
614→
615→  if (messages.empty()) {
616→    return;
617→  }
618→
619→  try {
620→    auto active_sessions = session_manager_->get_active_sessions();
621→    if (active_sessions.empty()) {
622→      return;
623→    }
624→
625→    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
626→    using GroupKey = std::map<std::string, int>;
627→    std::map<GroupKey, std::vector<std::string>> subscription_groups;
628→    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
629→
630→    for (const auto& client_id : active_sessions) {
631→      auto subs = session_manager_->get_subscriptions(client_id);
632→      if (subs.empty()) {
633→        continue;
634→      }
635→      GroupKey key;
636→      for (const auto& [topic, rate_hz] : subs) {
637→        key[topic] = static_cast<int>(rate_hz * 1000);
638→      }
639→      subscription_groups[key].push_back(client_id);
640→      client_subs[client_id] = std::move(subs);
641→    }
642→
643→    size_t total_msg_count = 0;
644→    size_t total_bytes = 0;
645→    std::unordered_map<std::string, uint64_t> forward_counts;
646→
647→    // Collect paused state outside of last_sent_mutex_ to avoid lock ordering issues.
648→    std::unordered_map<std::string, bool> paused_state;
649→    for (const auto& [group_key, client_ids] : subscription_groups) {
650→      for (const auto& client_id : client_ids) {
651→        paused_state[client_id] = session_manager_->is_paused(client_id);
652→      }
653→    }
654→
655→    // Per-group serialized frames, built under last_sent_mutex_ for rate limiting
656→    struct GroupFrame {
657→      std::vector<uint8_t> compressed_data;
658→      size_t msg_count;
659→      std::vector<std::string> client_ids;
660→    };
661→    std::vector<GroupFrame> frames;
662→
663→    {
664→      std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
665→
666→      for (const auto& [group_key, client_ids] : subscription_groups) {
667→        AggregatedMessageSerializer serializer;
668→        size_t group_msg_count = 0;
669→
670→        const auto& representative_subs = client_subs[client_ids.front()];
671→        auto& rep_last_sent = last_sent_times_[client_ids.front()];
672→
673→        for (const auto& [topic, msgs] : messages) {
674→          auto sub_it = representative_subs.find(topic);
675→          if (sub_it == representative_subs.end()) {
676→            continue;
677→          }
678→
679→          double rate_hz = sub_it->second;
680→          int rate_mhz = static_cast<int>(rate_hz * 1000);
681→
682→          if (rate_mhz == 0) {
683→            for (const auto& msg : msgs) {
684→              serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
685→              group_msg_count++;
686→              forward_counts[topic]++;
687→            }
688→          } else {
689→            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
690→            uint64_t last_sent = rep_last_sent[topic];
691→
692→            for (const auto& msg : msgs) {
693→              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
694→                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
695→                last_sent = msg.timestamp_ns;
696→                group_msg_count++;
697→                forward_counts[topic]++;
698→              }
699→            }
700→            rep_last_sent[topic] = last_sent;
701→          }
702→        }
703→
704→        if (group_msg_count == 0) {
705→          continue;
706→        }
707→
708→        GroupFrame frame;
709→        frame.compressed_data = serializer.finalize();
710→        frame.msg_count = group_msg_count;
711→        frame.client_ids = client_ids;
712→
713→        // Propagate rate-limiting state to other clients in the group
714→        for (const auto& client_id : client_ids) {
715→          if (client_id != client_ids.front()) {
716→            last_sent_times_[client_id] = rep_last_sent;
717→          }
718→        }
719→
720→        frames.push_back(std::move(frame));
721→      }
722→    }  // last_sent_mutex_ released here
723→
724→    // Send frames outside of any lock
725→    for (const auto& frame : frames) {
726→      bool any_sent = false;
727→      for (const auto& client_id : frame.client_ids) {
728→        auto it = paused_state.find(client_id);
729→        if (it != paused_state.end() && it->second) {
730→          continue;
731→        }
732→        if (middleware_->send_binary(client_id, frame.compressed_data)) {
733→          any_sent = true;
734→        } else {
735→          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
736→        }
737→      }
738→
739→      if (any_sent) {
740→        total_msg_count += frame.msg_count;
741→        total_bytes += frame.compressed_data.size();
742→      }
743→    }
744→
745→    if (total_msg_count > 0) {
746→      std::lock_guard<std::mutex> lock(stats_mutex_);
747→      total_messages_published_ += total_msg_count;
748→      total_bytes_published_ += total_bytes;
749→      publish_cycles_++;
750→      for (const auto& [topic, count] : forward_counts) {
751→        topic_forward_counts_[topic] += count;
752→      }
753→    }
754→  } catch (const std::exception& e) {
755→    spdlog::error("Error publishing aggregated messages: {}", e.what());
756→  }
757→}
