26→MessageBuffer::MessageBuffer(uint64_t max_message_age_ns) : max_message_age_ns_(max_message_age_ns) {}
27→
28→void MessageBuffer::add_message(
29→    const std::string& topic_name, uint64_t timestamp_ns, std::shared_ptr<std::vector<std::byte>> data) {
30→  std::lock_guard<std::mutex> lock(mutex_);
31→
32→  cleanup_old_messages();
33→
34→  BufferedMessage msg;
35→  msg.timestamp_ns = timestamp_ns;
36→  msg.received_at_ns = get_current_time_ns();
37→  msg.data = std::move(data);
38→
39→  topic_buffers_[topic_name].push_back(std::move(msg));
40→}
41→
42→void MessageBuffer::move_messages(std::unordered_map<std::string, std::deque<BufferedMessage>>& out_messages) {
43→  std::lock_guard<std::mutex> lock(mutex_);
44→  out_messages = std::move(topic_buffers_);
45→  topic_buffers_.clear();
46→}
47→
48→void MessageBuffer::clear() {
49→  std::lock_guard<std::mutex> lock(mutex_);
50→  topic_buffers_.clear();
51→}
52→
53→size_t MessageBuffer::size() const {
54→  std::lock_guard<std::mutex> lock(mutex_);
55→
56→  size_t total = 0;
57→  for (const auto& [topic, buffer] : topic_buffers_) {
58→    total += buffer.size();
59→  }
60→
61→  return total;
62→}
63→
64→void MessageBuffer::cleanup_old_messages() {
65→  uint64_t current_time = get_current_time_ns();
66→
67→  for (auto& [topic, buffer] : topic_buffers_) {
68→    while (!buffer.empty()) {
69→      const auto& oldest_msg = buffer.front();
70→      if (current_time - oldest_msg.received_at_ns > max_message_age_ns_) {
71→        buffer.pop_front();
72→      } else {
73→        break;
74→      }
75→    }
76→  }
77→
78→  for (auto it = topic_buffers_.begin(); it != topic_buffers_.end();) {
79→    if (it->second.empty()) {
80→      it = topic_buffers_.erase(it);
81→    } else {
82→      ++it;
83→    }
84→  }
85→}
