 29→WebSocketMiddleware::WebSocketMiddleware() : initialized_(false) {}
 30→
 31→WebSocketMiddleware::~WebSocketMiddleware() {
 32→  shutdown();
 33→}
 34→
 35→tl::expected<void, std::string> WebSocketMiddleware::initialize(uint16_t port) {
 36→  std::lock_guard<std::mutex> lock(state_mutex_);
 37→
 38→  if (initialized_) {
 39→    return tl::unexpected<std::string>("WebSocket middleware already initialized");
 40→  }
 41→
 42→  server_ = std::make_shared<ix::WebSocketServer>(port, "0.0.0.0");
 43→
 44→  server_->setOnClientMessageCallback([this](
 45→                                          std::shared_ptr<ix::ConnectionState> connection_state,
 46→                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 47→    {
 48→      std::lock_guard<std::mutex> state_lock(state_mutex_);
 49→      if (!initialized_) {
 50→        return;
 51→      }
 52→    }
 53→
 54→    std::string client_id = connection_state->getId();
 55→
 56→    if (msg->type == ix::WebSocketMessageType::Open) {
 57→      {
 58→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 59→        for (const auto& client : server_->getClients()) {
 60→          if (client.get() == &web_socket) {
 61→            clients_[client_id] = client;
 62→            break;
 63→          }
 64→        }
 65→      }
 66→
 67→      ConnectionCallback cb;
 68→      {
 69→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 70→        cb = on_connect_;
 71→      }
 72→      if (cb) {
 73→        cb(client_id);
 74→      }
 75→
 76→    } else if (msg->type == ix::WebSocketMessageType::Close) {
 77→      ConnectionCallback cb;
 78→      {
 79→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80→        cb = on_disconnect_;
 81→      }
 82→      if (cb) {
 83→        cb(client_id);
 84→      }
 85→
 86→      {
 87→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88→        clients_.erase(client_id);
 89→      }
 90→
 91→    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92→      if (!msg->binary) {
 93→        IncomingRequest req;
 94→        req.client_id = client_id;
 95→        req.data.assign(msg->str.begin(), msg->str.end());
 96→
 97→        {
 98→          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99→          if (incoming_queue_.size() >= kMaxIncomingQueueSize) {
100→            spdlog::warn(
101→                "Incoming queue full ({} messages), dropping message from client '{}'", kMaxIncomingQueueSize,
102→                client_id);
103→            return;
104→          }
105→          incoming_queue_.push(std::move(req));
106→        }
107→        queue_cv_.notify_one();
108→      }
109→    }
110→  });
111→
112→  auto listen_result = server_->listen();
113→  if (!listen_result.first) {
114→    server_.reset();
115→    return tl::unexpected<std::string>(
116→        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
117→  }
118→
119→  server_->start();
120→  initialized_ = true;
121→
122→  return {};
123→}
124→
125→void WebSocketMiddleware::shutdown() {
126→  std::shared_ptr<ix::WebSocketServer> server_to_stop;
127→
128→  {
129→    std::lock_guard<std::mutex> lock(state_mutex_);
130→
131→    if (!initialized_) {
132→      return;
133→    }
134→
135→    initialized_ = false;
136→    on_connect_ = nullptr;
137→    on_disconnect_ = nullptr;
138→    server_to_stop = std::move(server_);
139→  }
140→
141→  queue_cv_.notify_all();
142→
143→  if (server_to_stop) {
144→    // Replace the message callback with a no-op before stopping. The original
145→    // callback captures `this`, so it must not fire after the WebSocketMiddleware
146→    // instance is destroyed (which can happen if the stop thread is detached on timeout).
147→    server_to_stop->setOnClientMessageCallback(
148→        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
149→
150→    // Initiate graceful close on all connected clients before calling stop().
151→    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
152→    for (const auto& client : server_to_stop->getClients()) {
153→      client->close();
154→    }
155→
156→    // Run stop() on a dedicated thread with a timeout.
157→    spdlog::debug("[shutdown] Starting server stop thread...");
158→    auto done = std::make_shared<std::atomic<bool>>(false);
159→    std::thread stop_thread([server_to_stop, done]() {
160→      server_to_stop->stop();
161→      done->store(true);
162→    });
163→
164→    auto start = std::chrono::steady_clock::now();
165→    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
166→    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
167→      std::this_thread::sleep_for(std::chrono::milliseconds(50));
168→    }
169→    auto elapsed_ms =
170→        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
171→
172→    if (done->load()) {
173→      stop_thread.join();
174→      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
175→    } else {
176→      // Timeout reached. Detach the thread and let it finish in the background.
177→      // The thread captures server_to_stop by shared_ptr, so the server
178→      // will be destroyed when stop() finishes and the thread exits.
179→      // The message callback was already cleared above, so no use-after-free.
180→      spdlog::warn(
181→          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
182→          kShutdownTimeoutSeconds, elapsed_ms);
183→      stop_thread.detach();
184→    }
185→  }
186→
187→  {
188→    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
189→    clients_.clear();
190→  }
191→
192→  {
193→    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
194→    std::queue<IncomingRequest> empty;
195→    std::swap(incoming_queue_, empty);
196→  }
197→}
198→
199→bool WebSocketMiddleware::receive_request(std::vector<uint8_t>& data, std::string& client_identity) {
200→  {
201→    std::lock_guard<std::mutex> state_lock(state_mutex_);
202→    if (!initialized_) {
203→      return false;
204→    }
205→  }
206→
207→  std::unique_lock<std::mutex> lock(queue_mutex_);
208→
209→  if (!queue_cv_.wait_for(
210→          lock, std::chrono::milliseconds(kReceiveTimeoutMs), [this]() { return !incoming_queue_.empty(); })) {
211→    return false;
212→  }
213→
214→  auto req = std::move(incoming_queue_.front());
215→  incoming_queue_.pop();
216→
217→  data = std::move(req.data);
218→  client_identity = std::move(req.client_id);
219→  return true;
220→}
221→
222→bool WebSocketMiddleware::send_reply(const std::string& client_identity, const std::vector<uint8_t>& data) {
223→  std::shared_ptr<ix::WebSocket> ws;
224→  {
225→    std::lock_guard<std::mutex> lock(clients_mutex_);
226→    auto it = clients_.find(client_identity);
227→    if (it == clients_.end() || !it->second) {
228→      return false;
229→    }
230→    ws = it->second;
231→  }
232→
233→  std::string text_data(data.begin(), data.end());
234→  auto send_info = ws->send(text_data);
235→  return send_info.success;
236→}
237→
238→bool WebSocketMiddleware::send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) {
239→  std::shared_ptr<ix::WebSocket> ws;
240→  {
241→    std::lock_guard<std::mutex> lock(clients_mutex_);
242→    auto it = clients_.find(client_identity);
243→    if (it == clients_.end() || !it->second) {
244→      return false;
245→    }
246→    ws = it->second;
247→  }
248→
249→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
250→  auto send_info = ws->sendBinary(binary_data);
251→  return send_info.success;
252→}
253→
254→bool WebSocketMiddleware::publish_data(const std::vector<uint8_t>& data) {
255→  std::vector<std::shared_ptr<ix::WebSocket>> clients_copy;
256→  {
257→    std::lock_guard<std::mutex> lock(clients_mutex_);
258→    if (clients_.empty()) {
259→      return false;
260→    }
261→    clients_copy.reserve(clients_.size());
262→    for (const auto& [client_id, ws] : clients_) {
263→      if (ws) {
264→        clients_copy.push_back(ws);
265→      }
266→    }
267→  }
268→
269→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
270→  bool any_sent = false;
271→
272→  for (const auto& ws : clients_copy) {
273→    auto send_info = ws->sendBinary(binary_data);
274→    if (send_info.success) {
275→      any_sent = true;
276→    }
277→  }
278→
279→  return any_sent;
280→}
281→
282→bool WebSocketMiddleware::is_ready() const {
283→  std::lock_guard<std::mutex> lock(state_mutex_);
284→  return initialized_;
285→}
286→
287→void WebSocketMiddleware::set_on_connect(ConnectionCallback callback) {
288→  std::lock_guard<std::mutex> lock(state_mutex_);
289→  on_connect_ = std::move(callback);
290→}
291→
292→void WebSocketMiddleware::set_on_disconnect(ConnectionCallback callback) {
293→  std::lock_guard<std::mutex> lock(state_mutex_);
294→  on_disconnect_ = std::move(callback);
295→}
