38→class WebSocketMiddleware : public MiddlewareInterface {
39→ public:
40→  WebSocketMiddleware();
41→  ~WebSocketMiddleware() override;
42→
43→  WebSocketMiddleware(const WebSocketMiddleware&) = delete;
44→  WebSocketMiddleware& operator=(const WebSocketMiddleware&) = delete;
45→  WebSocketMiddleware(WebSocketMiddleware&&) = delete;
46→  WebSocketMiddleware& operator=(WebSocketMiddleware&&) = delete;
47→
48→  tl::expected<void, std::string> initialize(uint16_t port) override;
49→  void shutdown() override;
50→  bool receive_request(std::vector<uint8_t>& data, std::string& client_identity) override;
51→  bool send_reply(const std::string& client_identity, const std::vector<uint8_t>& data) override;
52→  bool publish_data(const std::vector<uint8_t>& data) override;
53→  bool send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) override;
54→  bool is_ready() const override;
55→  void set_on_connect(ConnectionCallback callback) override;
56→  void set_on_disconnect(ConnectionCallback callback) override;
57→
58→ private:
59→  struct IncomingRequest {
60→    std::string client_id;
61→    std::vector<uint8_t> data;
62→  };
63→
64→  std::shared_ptr<ix::WebSocketServer> server_;
65→
66→  std::queue<IncomingRequest> incoming_queue_;
67→  mutable std::mutex queue_mutex_;
68→  std::condition_variable queue_cv_;
69→
70→  std::unordered_map<std::string, std::shared_ptr<ix::WebSocket>> clients_;
71→  mutable std::mutex clients_mutex_;
72→
73→  ConnectionCallback on_connect_;
74→  ConnectionCallback on_disconnect_;
75→
76→  mutable std::mutex state_mutex_;
77→  bool initialized_;
78→
79→  static constexpr int kReceiveTimeoutMs = 10;
80→  static constexpr int kShutdownTimeoutSeconds = 3;
81→  static constexpr size_t kMaxIncomingQueueSize = 1024;
82→};
