 25→
 26→SessionManager::SessionManager(double timeout_seconds) : timeout_duration_(timeout_seconds) {}
 27→
 28→bool SessionManager::create_session(const std::string& client_id) {
 29→  std::lock_guard<std::mutex> lock(mutex_);
 30→
 31→  if (sessions_.find(client_id) != sessions_.end()) {
 32→    return false;
 33→  }
 34→
 35→  Session session;
 36→  session.client_id = client_id;
 37→  session.created_at = std::chrono::steady_clock::now();
 38→  session.last_heartbeat = session.created_at;
 39→
 40→  sessions_[client_id] = session;
 41→  return true;
 42→}
 43→
 44→bool SessionManager::update_heartbeat(const std::string& client_id) {
 45→  std::lock_guard<std::mutex> lock(mutex_);
 46→
 47→  auto it = sessions_.find(client_id);
 48→  if (it == sessions_.end()) {
 49→    return false;
 50→  }
 51→
 52→  it->second.last_heartbeat = std::chrono::steady_clock::now();
 53→  return true;
 54→}
 55→
 56→bool SessionManager::get_session(const std::string& client_id, Session& session) const {
 57→  std::lock_guard<std::mutex> lock(mutex_);
 58→
 59→  auto it = sessions_.find(client_id);
 60→  if (it == sessions_.end()) {
 61→    return false;
 62→  }
 63→
 64→  session = it->second;
 65→  return true;
 66→}
 67→
 68→bool SessionManager::update_subscriptions(
 69→    const std::string& client_id, const std::unordered_map<std::string, double>& topics) {
 70→  std::lock_guard<std::mutex> lock(mutex_);
 71→
 72→  auto it = sessions_.find(client_id);
 73→  if (it == sessions_.end()) {
 74→    return false;
 75→  }
 76→
 77→  it->second.subscribed_topics = topics;
 78→  return true;
 79→}
 80→
 81→bool SessionManager::add_subscription(const std::string& client_id, const std::string& topic, double rate) {
 82→  std::lock_guard<std::mutex> lock(mutex_);
 83→
 84→  auto it = sessions_.find(client_id);
 85→  if (it == sessions_.end()) {
 86→    return false;
 87→  }
 88→
 89→  it->second.subscribed_topics[topic] = rate;
 90→  return true;
 91→}
 92→
 93→bool SessionManager::remove_subscription(const std::string& client_id, const std::string& topic) {
 94→  std::lock_guard<std::mutex> lock(mutex_);
 95→
 96→  auto it = sessions_.find(client_id);
 97→  if (it == sessions_.end()) {
 98→    return false;
 99→  }
100→
101→  return it->second.subscribed_topics.erase(topic) > 0;
102→}
103→
104→std::unordered_map<std::string, double> SessionManager::get_subscriptions(const std::string& client_id) const {
105→  std::lock_guard<std::mutex> lock(mutex_);
106→
107→  auto it = sessions_.find(client_id);
108→  if (it == sessions_.end()) {
109→    return {};
110→  }
111→
112→  return it->second.subscribed_topics;
113→}
114→
115→bool SessionManager::remove_session(const std::string& client_id) {
116→  std::lock_guard<std::mutex> lock(mutex_);
117→
118→  auto it = sessions_.find(client_id);
119→  if (it == sessions_.end()) {
120→    return false;
121→  }
122→
123→  sessions_.erase(it);
124→  return true;
125→}
126→
127→std::vector<std::string> SessionManager::get_timed_out_sessions() {
128→  std::lock_guard<std::mutex> lock(mutex_);
129→
130→  std::vector<std::string> timed_out_clients;
131→  auto now = std::chrono::steady_clock::now();
132→
133→  for (const auto& [client_id, session] : sessions_) {
134→    auto time_since_heartbeat = now - session.last_heartbeat;
135→    if (time_since_heartbeat > timeout_duration_) {
136→      timed_out_clients.push_back(client_id);
137→    }
138→  }
139→
140→  return timed_out_clients;
141→}
142→
143→std::vector<std::string> SessionManager::get_active_sessions() const {
144→  std::lock_guard<std::mutex> lock(mutex_);
145→
146→  std::vector<std::string> active_sessions;
147→  active_sessions.reserve(sessions_.size());
148→
149→  for (const auto& [client_id, session] : sessions_) {
150→    active_sessions.push_back(client_id);
151→  }
152→
153→  return active_sessions;
154→}
155→
156→size_t SessionManager::session_count() const {
157→  std::lock_guard<std::mutex> lock(mutex_);
158→  return sessions_.size();
159→}
160→
161→bool SessionManager::session_exists(const std::string& client_id) const {
162→  std::lock_guard<std::mutex> lock(mutex_);
163→  return sessions_.find(client_id) != sessions_.end();
164→}
165→
166→bool SessionManager::set_paused(const std::string& client_id, bool paused) {
167→  std::lock_guard<std::mutex> lock(mutex_);
168→
169→  auto it = sessions_.find(client_id);
170→  if (it == sessions_.end()) {
171→    return false;
172→  }
173→
174→  it->second.paused = paused;
175→  return true;
176→}
177→
178→bool SessionManager::is_paused(const std::string& client_id) const {
179→  std::lock_guard<std::mutex> lock(mutex_);
180→
181→  auto it = sessions_.find(client_id);
182→  if (it == sessions_.end()) {
183→    return false;
184→  }
185→
186→  return it->second.paused;
187→}
