 70→std::vector<uint8_t> AggregatedMessageSerializer::finalize() {
 71→  // Build 16-byte header (uncompressed)
 72→  std::vector<uint8_t> header(kBinaryHeaderSize);
 73→
 74→  // Magic (offset 0, 4 bytes, little-endian)
 75→  uint32_t magic = kBinaryFrameMagic;
 76→  std::memcpy(header.data(), &magic, sizeof(magic));
 77→
 78→  // Message count (offset 4, 4 bytes, little-endian)
 79→  uint32_t count = static_cast<uint32_t>(message_count_);
 80→  std::memcpy(header.data() + 4, &count, sizeof(count));
 81→
 82→  // Uncompressed size (offset 8, 4 bytes, little-endian)
 83→  uint32_t uncompressed = static_cast<uint32_t>(serialized_data_.size());
 84→  std::memcpy(header.data() + 8, &uncompressed, sizeof(uncompressed));
 85→
 86→  // Flags (offset 12, 4 bytes, reserved = 0)
 87→  uint32_t flags = 0;
 88→  std::memcpy(header.data() + 12, &flags, sizeof(flags));
 89→
 90→  // Handle empty payload case
 91→  if (serialized_data_.empty()) {
 92→    return header;
 93→  }
 94→
 95→  // Compress the payload
 96→  size_t max_compressed = ZSTD_compressBound(serialized_data_.size());
 97→  std::vector<uint8_t> result(kBinaryHeaderSize + max_compressed);
 98→
 99→  // Copy header to output
100→  std::memcpy(result.data(), header.data(), kBinaryHeaderSize);
101→
102→  // Compress payload after header using persistent context
103→  size_t compressed_size = ZSTD_compressCCtx(
104→      cctx_, result.data() + kBinaryHeaderSize, max_compressed, serialized_data_.data(), serialized_data_.size(),
105→      1  // compression level
106→  );
107→
108→  if (ZSTD_isError(compressed_size)) {
109→    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
110→  }
111→
112→  // Resize to actual size: header + compressed payload
113→  result.resize(kBinaryHeaderSize + compressed_size);
114→  return result;
115→}
116→
117→void AggregatedMessageSerializer::compress_zstd(
118→    const std::vector<uint8_t> &data, std::vector<uint8_t> &compressed_data) {
119→  compressed_data.clear();
120→  if (data.empty()) {
121→    return;
122→  }
123→
124→  // Get maximum compressed size
125→  size_t max_compressed_size = ZSTD_compressBound(data.size());
126→  compressed_data.resize(max_compressed_size);
127→
128→  // Compress (static helper — uses one-shot API; hot path uses finalize() with persistent cctx_)
129→  size_t compressed_size = ZSTD_compress(compressed_data.data(), compressed_data.size(), data.data(), data.size(), 1);
130→
131→  // Check for errors
132→  if (ZSTD_isError(compressed_size)) {
133→    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
134→  }
135→
136→  // Resize to actual compressed size
137→  compressed_data.resize(compressed_size);
138→}
139→
140→void AggregatedMessageSerializer::decompress_zstd(
141→    const std::vector<uint8_t> &compressed_data, std::vector<uint8_t> &decompressed) {
142→  decompressed.clear();
143→  if (compressed_data.empty()) {
144→    return;
145→  }
146→
147→  // Get decompressed size
148→  unsigned long long decompressed_size = ZSTD_getFrameContentSize(compressed_data.data(), compressed_data.size());
149→
150→  if (decompressed_size == ZSTD_CONTENTSIZE_ERROR) {
151→    throw std::runtime_error("ZSTD: not compressed by zstd");
152→  }
153→  if (decompressed_size == ZSTD_CONTENTSIZE_UNKNOWN) {
154→    throw std::runtime_error("ZSTD: original size unknown");
155→  }
156→  decompressed.resize(decompressed_size);
157→
158→  // Decompress using persistent context
159→  ZSTD_DCtx *dctx = get_dctx();
160→  size_t result = ZSTD_decompressDCtx(
161→      dctx, decompressed.data(), decompressed.size(), compressed_data.data(), compressed_data.size());
162→
163→  // Check for errors
164→  if (ZSTD_isError(result)) {
165→    throw std::runtime_error(std::string("ZSTD decompression failed: ") + ZSTD_getErrorName(result));
166→  }
167→}
168→
169→template <typename T>
170→void AggregatedMessageSerializer::write_le(std::vector<uint8_t> &buffer, T value) {
171→  // Write value in little-endian format
172→  for (size_t i = 0; i < sizeof(T); ++i) {
173→    buffer.push_back(static_cast<uint8_t>((value >> (i * 8)) & 0xFF));
174→  }
175→}
176→
177→void AggregatedMessageSerializer::write_str(std::vector<uint8_t> &buffer, const std::string &str) {
178→  // Write string length
179→  write_le<uint16_t>(buffer, static_cast<uint16_t>(str.size()));
180→  // Write string data
181→  buffer.insert(buffer.end(), str.begin(), str.end());
